function solve(nums, queries) {
    if (nums.length === 0) return [];
    const distinctSet = new Set(nums);
    const sorted = Array.from(distinctSet).sort((a, b) => a - b);
    const map = {};
    for (let i = 0; i < sorted.length; i++) {
        map[sorted[i]] = i;
    }
    const compressed = nums.map(val => map[val]);
    const d = sorted.length;
    const freArr = new Array(d).fill(0);
    const lastUsed = new Array(d).fill(-1);
    const ans = [];

    for (let j = 0; j < queries.length; j++) {
        const [l, r, thres] = queries[j];
        let curMax = 0;
        let candidate = -1;
        for (let i = l; i <= r; i++) {
            const x = compressed[i];
            if (lastUsed[x] !== j) {
                freArr[x] = 0;
                lastUsed[x] = j;
            }
            freArr[x]++;
            const cnt = freArr[x];
            if (cnt > curMax) {
                curMax = cnt;
                candidate = x;
            } else if (cnt === curMax && x < candidate) {
                candidate = x;
            }
        }
        ans.push(curMax >= thres ? sorted[candidate] : -1);
    }
    return ans;
}
